def _drain_lines(self, session: FirmwareSession, duration_s: float = 1.5) -> list[str]:
    deadline = time.monotonic() + duration_s
    lines: list[str] = []
    while time.monotonic() < deadline:
        lines.extend(session.read_lines(timeout_s=0.1))
    return lines
